class TokenBucket:
    __slots__ = ("rate", "capacity", "tokens", "ts")

    def __init__(self, rate_per_sec: float, capacity: float):
        self.rate = float(rate_per_sec)
        self.capacity = float(capacity)
        self.tokens = float(capacity)
        self.ts = time.monotonic()

    def allow(self, cost: float = 1.0) -> bool:
        t = time.monotonic()
        dt = t - self.ts
        self.ts = t
        self.tokens = min(self.capacity, self.tokens + dt * self.rate)
        if self.tokens >= cost:
            self.tokens -= cost
            return True
        return False


class RateLimiter:
    def __init__(self, rate_per_ip_per_sec: float, burst: float, ttl_sec: float):
        self.rate = rate_per_ip_per_sec
        self.burst = burst
        self.ttl = ttl_sec
        self.buckets: Dict[str, Tuple[TokenBucket, float]] = {}

    def allow(self, ip: str, cost: float = 1.0) -> bool:
        t = time.monotonic()
        item = self.buckets.get(ip)
        if item is None:
            b = TokenBucket(self.rate, self.burst)
            self.buckets[ip] = (b, t)
            return b.allow(cost)
        b, last = item
        self.buckets[ip] = (b, t)
        return b.allow(cost)

    def gc(self) -> None:
        t = time.monotonic()
        dead = [ip for ip, (_, last) in self.buckets.items() if (t - last) > self.ttl]
        for ip in dead:
            self.buckets.pop(ip, None)


def build_status_payload(state: GameState) -> bytes:
    body = json.dumps(state.to_status_dict(), separators=(",", ":"), ensure_ascii=False).encode("utf-8")
