def maybe_compress(data: bytes, threshold: int = 800) -> Tuple[bytes, bool]:
    if len(data) < threshold:
        return data, False
    comp = zlib.compress(data, level=6)
    if len(comp) + 16 < len(data):
        return comp, True
    return data, False


def fragment_bytes(data: bytes, max_payload: int) -> List[bytes]:
    if len(data) <= max_payload:
        return [data]
    frags = []
    off = 0
    while off < len(data):
        frags.append(data[off : off + max_payload])
        off += max_payload
    return frags


def pack_response(
    query_id: int,
    body: bytes,
    compress: bool,
    mtu: int,
    frag_payload: int,
) -> List[bytes]:
    # Header:
    # magic(4) type(1) flags(1) query_id(4) total_len(4) frag_id(2) frag_count(2) frag_off(4) frag_len(2)
    # total header = 4+1+1+4+4+2+2+4+2 = 26 bytes
    header_len = 26
    max_dgram = min(MAX_DGRAM_SIZE, mtu)
    max_payload = max(1, min(frag_payload, max_dgram - header_len))
    frags = fragment_bytes(body, max_payload)
    frag_count = len(frags)
    flags = 0
    if compress:
        flags |= FLAG_COMPRESSED
    if frag_count > 1:
        flags |= FLAG_FRAGMENTED

    total_len = len(body)
    packets = []
    offset = 0
    for i, frag in enumerate(frags):
        frag_len = len(frag)
        hdr = bytearray()
        hdr += MAGIC
        hdr += bytes([MSG_STATUS_RSP])
        hdr += bytes([flags])
        hdr += int(query_id & 0xFFFFFFFF).to_bytes(4, "big", signed=False)
        hdr += int(total_len & 0xFFFFFFFF).to_bytes(4, "big", signed=False)
        hdr += int(i & 0xFFFF).to_bytes(2, "big", signed=False)
        hdr += int(frag_count & 0xFFFF).to_bytes(2, "big", signed=False)
        hdr += int(offset & 0xFFFFFFFF).to_bytes(4, "big", signed=False)
        hdr += int(frag_len & 0xFFFF).to_bytes(2, "big", signed=False)
        packets.append(bytes(hdr) + frag)
        offset += frag_len
    return packets


def parse_status_request(data: bytes) -> Optional[Tuple[int, Dict[str, Any]]]:
    # Request format:
    # magic(4) type(1=STATUS_REQ) query_id(4) flags(1) json_len(2) json(...)
    # total header = 12 bytes
    if len(data) < 12:
        return None
    if data[:4] != MAGIC:
        return None
    if data[4] != MSG_STATUS_REQ:
        return None
    query_id = int.from_bytes(data[5:9], "big", signed=False)
    _flags = data[9]
    jlen = int.from_bytes(data[10:12], "big", signed=False)
    if 12 + jlen > len(data):
        return None
    opts = {}
    if jlen:
        try:
            opts = json.loads(data[12 : 12 + jlen].decode("utf-8"))
            if not isinstance(opts, dict):
                opts = {}
        except Exception:
            opts = {}
    return query_id, opts


class GameUDPServer(asyncio.DatagramProtocol):
    def __init__(
        self,
        state: GameState,
        mtu: int = DEFAULT_MTU,
        frag_payload: int = DEFAULT_FRAG_PAYLOAD,
        rate_limiter: Optional[RateLimiter] = None,
        compress_threshold: int = 800,
    ):
        self.state = state
        self.transport: Optional[asyncio.DatagramTransport] = None
        self.mtu = mtu
        self.frag_payload = frag_payload
        self.rate_limiter = rate_limiter
        self.compress_threshold = compress_threshold
        self._last_gc = time.monotonic()

    def connection_made(self, transport):
        self.transport = transport
        sock = transport.get_extra_info("socket")
        if sock is not None:
            try:
                sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 4 * 1024 * 1024)
                sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 4 * 1024 * 1024)
            except Exception:
                pass

    def datagram_received(self, data, addr):
        ip, port = addr[0], addr[1]

        if self.rate_limiter is not None:
            if not self.rate_limiter.allow(ip, cost=1.0):
                return
            t = time.monotonic()
            if (t - self._last_gc) > 2.0:
                self._last_gc = t
                self.rate_limiter.gc()

        req = parse_status_request(data)
        if req is None:
            return
        query_id, opts = req

        status_dict = self.state.to_status_dict()

        # Allow basic filters without excluding full list by default
        # opts may include: include_players(bool), include_state(bool)
        include_players = opts.get("include_players", True)
        include_state = opts.get("include_state", True)
        if not include_players:
            status_dict["players"] = []
            status_dict["num_players"] = len(self.state.players)
        if not include_state:
            for k in ("map", "mode", "round", "uptime_ms", "properties", "server_name", "max_players"):
                status_dict.pop(k, None)

        body = json.dumps(status_dict, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        body2, compressed = maybe_compress(body, threshold=self.compress_threshold)

        packets = pack_response(
            query_id=query_id,
            body=body2,
            compress=compressed,
            mtu=self.mtu,
            frag_payload=self.frag_payload,
        )

        if self.transport is None:
            return
        for pkt in packets:
            try:
                self.transport.sendto(pkt, addr)
            except Exception:
                break

    def error_received(self, exc):
        pass


