    parser.add_argument("--frag-payload", type=int, default=safe_get_mtu(os.environ.get("GSV_FRAG_PAYLOAD", ""), DEFAULT_FRAG_PAYLOAD))
    parser.add_argument("--compress-threshold", type=int, default=800)
    parser.add_argument("--rate", type=float, default=DEFAULT_MAX_RPS, help="per-IP requests/sec")
    parser.add_argument("--burst", type=float, default=DEFAULT_BUCKET_SIZE, help="per-IP burst")
    parser.add_argument("--no-rate-limit", action="store_true")
    parser.add_argument("--seed-players", type=int, default=0, help="seed fake players for testing large responses")
